import json, os, glob, re

# For dataset0206/train, map vmfb_name -> (shape, config_idx, tile_sizes)
path = '/local/nick/ai_iree/dataset0206/train'
vmfb_to_info = {}
for f in sorted(glob.glob(f'{path}/compile_report_worker_*.json')):
    d = json.load(open(f))
    for op, shapes in d.items():
        for shape_key, entry in shapes.items():
            shape_id = entry['id']
            # Baseline
            bl = entry.get('baseline', {})
            if bl.get('vmfb_path'):
                bn = os.path.basename(bl['vmfb_path'])
                vmfb_to_info[bn] = (shape_key, 'baseline', bl['tile_sizes'])
            # Configs
            for c in entry.get('lowering_configs', []):
                if c.get('vmfb_path') and c['vmfb_path'] != 'N/A':
                    bn = os.path.basename(c['vmfb_path'])
                    vmfb_to_info[bn] = (shape_key, c['config_idx'], c['tile_sizes'])

print(f'Total vmfb entries in compile reports: {len(vmfb_to_info)}')

# Now load TSV and match
tsv_results = {}
for f in sorted(glob.glob(f'{path}/manifest_*_result.tsv')):
    with open(f) as fh:
        for line in fh:
            line = line.strip()
            if not line or line.startswith('#'):
                continue
            parts = line.split('\t')
            if len(parts) >= 3:
                tsv_results[parts[0]] = (parts[1], parts[2])

matched = 0
unmatched_tsv = []
for vmfb_name, (status, latency) in tsv_results.items():
    if vmfb_name in vmfb_to_info:
        matched += 1
    else:
        unmatched_tsv.append(vmfb_name)

print(f'TSV entries: {len(tsv_results)}, matched: {matched}, unmatched: {len(unmatched_tsv)}')
if unmatched_tsv:
    print(f'First 5 unmatched: {unmatched_tsv[:5]}')

# Show a few matched examples
count = 0
for vmfb_name, (status, latency) in tsv_results.items():
    if vmfb_name in vmfb_to_info and status == 'P':
        shape, cfg_idx, tile_sizes = vmfb_to_info[vmfb_name]
        print(f'  {vmfb_name}: shape={shape}, cfg={cfg_idx}, latency={latency}')
        print(f'    tiles={tile_sizes}')
        count += 1
        if count >= 3:
            break
