from collections import defaultdict

# For dataset0206 train: analyze shape-to-config distribution for shapes that have benchmark data
path = '/local/nick/ai_iree/dataset0206/train'

# Build vmfb -> (shape, config_idx, tile_sizes) mapping
vm = {}
for f in sorted(glob.glob(f'{path}/compile_report_worker_*.json')):
    d = json.load(open(f))
    for op, shapes in d.items():
        for sk, e in shapes.items():
            bl = e.get('baseline', {})
            bvp = bl.get('vmfb_path', '')
            if bvp: vm[os.path.basename(bvp)] = (sk, 'baseline', bl.get('tile_sizes'))
            for c in e.get('lowering_configs', []):
                vp = c.get('vmfb_path', '')
                if vp and vp not in ('', 'N/A'):
                    vm[os.path.basename(vp)] = (sk, c['config_idx'], c['tile_sizes'])

# Load TSV results
shape_configs = defaultdict(list)  # shape -> [(config_idx, tile_sizes, latency)]
for f in sorted(glob.glob(f'{path}/manifest_*_result.tsv')):
    with open(f) as fh:
        for line in fh:
            line = line.strip()
            if not line or line.startswith('#'): continue
            parts = line.split(chr(9))
            if len(parts) >= 3 and parts[0] in vm:
                sk, ci, ts = vm[parts[0]]
                shape_configs[sk].append((ci, ts, parts[1], parts[2]))

# Stats
shapes_with_p = {}
for sk, configs in shape_configs.items():
    p_configs = [(ci, ts, lat) for ci, ts, st, lat in configs if st == 'P']
    if p_configs:
        shapes_with_p[sk] = p_configs

print(f'Shapes with any benchmark: {len(shape_configs)}')
print(f'Shapes with P configs: {len(shapes_with_p)}')

# Distribution of P configs per shape
counts = sorted([len(v) for v in shapes_with_p.values()])
print(f'P configs per shape: min={min(counts)}, max={max(counts)}, median={counts[len(counts)//2]}, mean={sum(counts)/len(counts):.1f}')

# Show a few examples
for sk in list(shapes_with_p.keys())[:3]:
    p = shapes_with_p[sk]
    lats = [int(l) for _, _, l in p]
    print(f'  {sk}: {len(p)} P configs, latency range: {min(lats)/1e6:.1f}ms - {max(lats)/1e6:.1f}ms')
